const body = $input.first()?.json?.body || {};
const dataType = body.type || 'general';
// Types: interaction (user clicked/saved/starred), feedback (accept/reject), observation (OODA result), intel (SITREP/alert), search (user search query), opportunity (opp data), custom

const dataPoint = {
  type: dataType,
  source: body.source || 'unknown',
  content: body.content || '',
  metadata: body.metadata || {},
  user_context: body.user_context || '',
  timestamp: new Date().toISOString()
};

return [{ json: dataPoint }];

// Every 50th data point, flag for trend analysis
const pgResult = $('Store in Postgres').first()?.json;
const id = pgResult?.id || 0;
const shouldAnalyze = (id % 50 === 0);

return [{ json: { should_analyze_trends: shouldAnalyze, data_point_id: id, data_type: $('Classify Data Point').first()?.json?.type || 'general' } }];
